// // This comment suggests that the output Y is HIGH only when any of the inputs A1, A2, A3, or A4 is HIGH, but it actually requires all of them to be LOW for Y to be LOW.
module top_module(
    input A1,
    input A2,
    input A3,
    input A4,
    input B1,
    output Y
);assign Y = (A1 & A2 & A3 & A4) | B1;

endmodule
